{
  "schemaVersion": 1,
  "scenarioId": "eval-complex-human-planning-and-match",
  "extraction": {
    "title": "Support and sales ops migration to HubSpot with automations, handoff docs, and operator training",
    "summary": "Migrate support ops from Notion and Airtable to HubSpot, set up automations, produce handoff docs, and provide operator training that remains maintainable by the team (avoid black-box setup). Timeline target is about three weeks and budget is around 6k to 9k.",
    "seeking": {
      "actorKinds": [
        "human"
      ],
      "supplyKinds": [
        "operator",
        "migration_lead",
        "automation_builder",
        "documentation_support"
      ]
    },
    "outputKinds": [
      "migration_plan",
      "workflow_build",
      "handoff_doc",
      "operator_training"
    ],
    "missingDetails": [
      "Notion and Airtable data scope (tables/forms, workflows, fields) and target HubSpot objects (contacts, companies, tickets, etc.)",
      "Exact three-week start date and whether there are fixed milestones or weekly check-ins",
      "What “support in Notion” specifically means (e.g., knowledge base, ticketing, intake forms)",
      "Automation requirements details (handoff triggers, SLA logic, routing, integrations) and any existing systems to integrate",
      "Training format and who the operators are (roles, number of trainees, required competencies)",
      "Acceptance criteria and how handoff success will be verified by the team"
    ],
    "constraints": {
      "budgetCurrency": "USD",
      "budgetMin": 6000,
      "budgetMax": 9000,
      "timeWindow": {
        "durationEstimate": "3_weeks"
      },
      "avoid_black_box_setup": true,
      "ai_support_allowed": true
    }
  },
  "routing": {
    "routeFamily": "direct_specialist",
    "complexityLevel": "medium",
    "needsPlan": true,
    "humanRequired": true,
    "needsClarification": true
  },
  "planning": {
    "leadRole": "migration_lead",
    "executionProfile": {
      "executionModes": [
        "migration_planning",
        "hubspot_workflow_setup",
        "enablement_and_training"
      ],
      "requiresHumanPresence": false,
      "requiresLocalAccess": false,
      "requiresVerifiedEvidence": false,
      "requiresScheduling": true,
      "requiresGeography": false,
      "riskTier": "medium"
    },
    "verificationPlan": {
      "requiredArtifactKinds": [
        "migration_plan",
        "workflow_build",
        "handoff_doc",
        "operator_training"
      ],
      "requiredEvidenceClaims": [
        "team can run/modify automations without vendor-only black-box dependencies",
        "handoff docs cover configuration, triggers, owners, and change process"
      ],
      "mustHaveOwnerAcceptance": true,
      "mustHaveLocationSignal": false,
      "mustHaveSignature": false
    },
    "planCollapseRisk": {
      "riskLevel": "medium",
      "reasons": [
        "Scope of Notion/Airtable usage and exact HubSpot target objects is not specified",
        "Automation and handoff logic requirements are not detailed",
        "Training and acceptance criteria are not defined"
      ]
    },
    "phases": [
      {
        "phaseKey": "phase_1_discovery_and_scope",
        "title": "Discovery and migration scope definition (3-week plan + data/workflow mapping)"
      },
      {
        "phaseKey": "phase_2_hubspot_setup_and_automation_build",
        "title": "HubSpot configuration and automations build (maintainable by team)"
      },
      {
        "phaseKey": "phase_3_handoff_docs_and_operator_training",
        "title": "Handoff documentation and operator training (no black-box ownership)"
      },
      {
        "phaseKey": "phase_4_owner_acceptance",
        "title": "Team acceptance and rollout readiness check"
      }
    ],
    "roleSlots": [
      {
        "roleKey": "migration_lead",
        "requiredActorKinds": [
          "human"
        ],
        "required": true
      },
      {
        "roleKey": "automation_builder",
        "requiredActorKinds": [
          "agent",
          "human"
        ],
        "required": false
      },
      {
        "roleKey": "documentation_support",
        "requiredActorKinds": [
          "human"
        ],
        "required": false
      }
    ],
    "noMicrotaskExplosion": true
  },
  "matching": {
    "leadRanking": [
      "sup_human_ops_migration_lead",
      "sup_ai_automation_studio",
      "sup_copy_only_documentation_team",
      "sup_generic_chat_agent"
    ],
    "roleMatches": {
      "migration_lead": "sup_human_ops_migration_lead",
      "automation_builder": "sup_ai_automation_studio",
      "documentation_support": "sup_copy_only_documentation_team"
    }
  },
  "policy": {
    "nextAction": "clarify_request",
    "requiresOwnerApproval": true,
    "shouldOpenRequest": true,
    "shouldCreateFulfillment": false,
    "shouldCreateFulfillmentSteps": false
  }
}

